.scroll-track { min-height: 240vh; }
.sticky-stage { position: sticky; top: 0; height: 100vh; display: flex; align-items: center; justify-content: center; }
body { background: rgb(8,9,10); will-change: background-color; }

var BG = [[8,9,10],[16,30,72],[244,238,226]];     /* 다크 → 딥블루 → 크림 */
var FG = [[255,255,255],[235,240,255],[17,17,17]]; /* 텍스트 카운터 색 */
function mix(a, b, t){
  return "rgb(" + Math.round(a[0] + (b[0] - a[0]) * t) + ","
    + Math.round(a[1] + (b[1] - a[1]) * t) + ","
    + Math.round(a[2] + (b[2] - a[2]) * t) + ")";
}
function pick(stops, p){
  var seg = p < 0.5 ? 0 : 1;
  var t = Math.max(0, Math.min(1, seg === 0 ? p / 0.5 : (p - 0.5) / 0.5));
  return mix(stops[seg], stops[seg + 1], t);
}
var track = document.querySelector(".scroll-track");
var head = document.querySelector(".stage-head");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  document.body.style.backgroundColor = pick(BG, p);
  head.style.color = pick(FG, p);
}, { passive: true });

var DARK = [8,9,10], LIGHT = [246,245,242];
function mix(a, b, t){
  return "rgb(" + Math.round(a[0] + (b[0] - a[0]) * t) + ","
    + Math.round(a[1] + (b[1] - a[1]) * t) + ","
    + Math.round(a[2] + (b[2] - a[2]) * t) + ")";
}
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var t = Math.max(0, Math.min(1, (p - 0.4) / 0.2));   /* 플립 구간 [0.4, 0.6] */
  document.body.style.backgroundColor = mix(DARK, LIGHT, t);
  document.body.style.color = mix([255,255,255], [17,17,17], t);
}, { passive: true });

var A1 = [10,14,40], A2 = [88,16,104];    /* 시작 색: 딥네이비 → 퍼플 */
var B1 = [36,12,72], B2 = [255,122,64];   /* 끝 색: 다크바이올렛 → 오렌지 */
function mix(a, b, t){
  return "rgb(" + Math.round(a[0] + (b[0] - a[0]) * t) + ","
    + Math.round(a[1] + (b[1] - a[1]) * t) + ","
    + Math.round(a[2] + (b[2] - a[2]) * t) + ")";
}
var bg = document.querySelector(".grad-bg");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var angle = 135 + 180 * p;                /* 135° → 315° */
  bg.style.background = "linear-gradient(" + angle + "deg, " + mix(A1, A2, p) + ", " + mix(B1, B2, p) + ")";
}, { passive: true });

.sticky-stage { position: sticky; top: 0; height: 100vh; overflow: hidden; background: rgb(8,9,10); }
.wipe-layer { position: absolute; inset: 0; background: rgb(76,48,178); clip-path: circle(0% at 50% 50%); will-change: clip-path; }
.wipe-copy { position: relative; z-index: 2; }

var layer = document.querySelector(".wipe-layer");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  layer.style.clipPath = "circle(" + (p * 150) + "% at 50% 50%)";  /* 150%면 코너까지 커버 */
}, { passive: true });

var BG = [[8,9,10],[244,196,72],[18,22,56]];  /* 다크 → 앰버 → 딥네이비 */
function mixArr(a, b, t){
  return [Math.round(a[0]+(b[0]-a[0])*t), Math.round(a[1]+(b[1]-a[1])*t), Math.round(a[2]+(b[2]-a[2])*t)];
}
var head = document.querySelector(".lum-head");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var seg = p < 0.5 ? 0 : 1;
  var t = Math.max(0, Math.min(1, seg === 0 ? p / 0.5 : (p - 0.5) / 0.5));
  var c = mixArr(BG[seg], BG[seg + 1], t);
  document.body.style.backgroundColor = "rgb(" + c[0] + "," + c[1] + "," + c[2] + ")";
  /* 상대 휘도 → 텍스트 카운터 보간 */
  var lum = (0.2126 * c[0] + 0.7152 * c[1] + 0.0722 * c[2]) / 255;
  var k = Math.max(0, Math.min(1, (lum - 0.35) / 0.2));
  var fg = mixArr([255,255,255], [17,17,17], k);
  head.style.color = "rgb(" + fg[0] + "," + fg[1] + "," + fg[2] + ")";
}, { passive: true });

:root { --accent: hsl(220, 88%, 62%); }
.acc { color: var(--accent); }
.acc-btn { background: var(--accent); color: #0a0a0c; }

var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var hue = Math.round(220 + 180 * p) % 360;   /* 220° → 320° → 40° */
  /* CSS 변수 하나만 갱신하면 var(--accent)를 참조하는 모든 컴포넌트가 따라온다 */
  document.documentElement.style.setProperty("--accent", "hsl(" + hue + ", 88%, 62%)");
}, { passive: true });

.scene { position: relative; aspect-ratio: 16 / 9; border-radius: 24px; overflow: hidden; }
.s-sun { position: absolute; width: 22%; aspect-ratio: 1; border-radius: 50%; left: 16%; top: 13%; }
.s-hill { position: absolute; width: 92%; aspect-ratio: 2.6 / 1; border-radius: 50%; bottom: -34%; }

var A = [[44,62,148],[142,52,180],[16,108,84]];   /* 주조: 네이비 → 퍼플 → 그린 */
var B = [[122,222,198],[255,152,112],[248,208,88]]; /* 보조: 민트 → 코랄 → 옐로 */
function mixArr(a, b, t){
  return [Math.round(a[0]+(b[0]-a[0])*t), Math.round(a[1]+(b[1]-a[1])*t), Math.round(a[2]+(b[2]-a[2])*t)];
}
function rgbStr(c){ return "rgb(" + c[0] + "," + c[1] + "," + c[2] + ")"; }
function pickArr(stops, p){
  var seg = p < 0.5 ? 0 : 1;
  var t = Math.max(0, Math.min(1, seg === 0 ? p / 0.5 : (p - 0.5) / 0.5));
  return mixArr(stops[seg], stops[seg + 1], t);
}
var scene = document.querySelector(".scene");
var sun = document.querySelector(".s-sun");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var a = pickArr(A, p), b = pickArr(B, p);
  scene.style.background = "linear-gradient(165deg, " + rgbStr(a) + ", " + rgbStr(mixArr(a, b, 0.4)) + ")";
  sun.style.backgroundColor = rgbStr(b);
}, { passive: true });

.split-layer { position: absolute; inset: 0; display: flex; align-items: center; justify-content: center; }
.split-base { background: rgb(8,9,10); color: #fff; }
.split-next { background: rgb(244,238,226); color: #141414; clip-path: polygon(0% 0%, 0% 0%, -45% 100%, 0% 100%); will-change: clip-path; }

var next = document.querySelector(".split-next");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var e = p * 165;   /* 위 변 0→165%, 아래 변은 -45% 오프셋으로 기울기 고정 */
  next.style.clipPath = "polygon(0% 0%, " + e + "% 0%, " + (e - 45) + "% 100%, 0% 100%)";
}, { passive: true });

.strip { position: absolute; inset: 0 0 auto; height: 300%; will-change: transform; }
.sec { height: 33.3334%; }
.mini-nav { position: absolute; top: 0; left: 0; right: 0; z-index: 10; color: #fff; }
.mini-nav a { color: inherit; }
.nav-cta { border: 1px solid currentColor; border-radius: 999px; padding: 8px 16px; }

var NAVC = [[255,255,255],[17,17,17],[255,255,255]];  /* 섹션별 내비 카운터 색 */
function mix(a, b, t){
  return "rgb(" + Math.round(a[0] + (b[0] - a[0]) * t) + ","
    + Math.round(a[1] + (b[1] - a[1]) * t) + ","
    + Math.round(a[2] + (b[2] - a[2]) * t) + ")";
}
var strip = document.querySelector(".strip");
var nav = document.querySelector(".mini-nav");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  strip.style.transform = "translateY(" + (-p * 66.6667) + "%)";
  /* 내비가 보고 있는 스트립 좌표(vh) → 섹션 인덱스 + 경계 보간 */
  var navY = p * 200 + 8;
  var idx = Math.min(2, Math.floor(navY / 100));
  var frac = navY - idx * 100;
  var blend = idx < 2 ? Math.max(0, Math.min(1, (frac - 92) / 8)) : 0;
  nav.style.color = mix(NAVC[idx], NAVC[Math.min(2, idx + 1)], blend);
}, { passive: true });

.hue-art { position: absolute; inset: 0; will-change: filter; }
.blob { position: absolute; border-radius: 50%; }
.blob-1 { width: 46vw; height: 46vw; background: radial-gradient(circle at 35% 35%, rgb(47,107,255), transparent 70%); }
/* 카피·HUD는 .hue-art 밖에 두어 hue 영향을 받지 않게 */

var art = document.querySelector(".hue-art");
var hud = document.querySelector(".hue-hud");
var track = document.querySelector(".scroll-track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var deg = Math.round(p * 360);   /* 진행률 = 색상환 각도 */
  art.style.filter = "hue-rotate(" + deg + "deg)";
  hud.textContent = "HUE " + deg + "\u00B0";
}, { passive: true });
